import React from "react";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

const GRADIENTS = {
  briefcase: "linear-gradient(135deg, #434343 0%, black 100%)",
  university: "linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)",
  cloud: "linear-gradient(135deg, #0072c6 0%, #00a1f1 100%)",
};

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022 - Present",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021 - 2022",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014 - 2021",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013 - 2014",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008 - 2013",
    icon: <FaBriefcase />,
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001 - 2008",
    icon: <FaBriefcase />,
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001 - 2006",
    icon: <FaUniversity />,
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2023 - 2024",
    icon: <FaUniversity />,
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022 - 2024",
    icon: <FaUniversity />,
  },
];

const getColorsByIcon = (icon) => {
  if (icon.type === FaBriefcase) {
    return {
      iconBgGradient: GRADIENTS.briefcase,
      contentBgGradient: GRADIENTS.briefcase,
      arrowBorderColor: "black",
    };
  } else if (icon.type === FaUniversity) {
    return {
      iconBgGradient: GRADIENTS.university,
      contentBgGradient: GRADIENTS.university,
      arrowBorderColor: "#3b82f6",
    };
  } else if (icon.type === FaCloud) {
    return {
      iconBgGradient: GRADIENTS.cloud,
      contentBgGradient: GRADIENTS.cloud,
      arrowBorderColor: "#00a1f1",
    };
  }
  return {
    iconBgGradient: "#888",
    contentBgGradient: "#ccc",
    arrowBorderColor: "#ccc",
  };
};

const parseStartYear = (dateStr) => {
  const match = dateStr.match(/^(\d{4})/);
  return match ? parseInt(match[1], 10) : 0;
};

export default function ExperienceTimeline() {
  const sortedData = [...experienceData].sort(
    (a, b) => parseStartYear(b.date) - parseStartYear(a.date)
  );

  return (
    <VerticalTimeline>
      {sortedData.map((exp, idx) => {
        const { iconBgGradient, contentBgGradient, arrowBorderColor } =
          getColorsByIcon(exp.icon);
        const isUniversityOrCloud =
          exp.icon.type === FaUniversity || exp.icon.type === FaCloud;

        return (
          <VerticalTimelineElement
            key={idx}
            date={
              <span
                style={{
                  fontWeight: "bold",
                  color: "white",
                  fontSize: "1.1rem",
                  textShadow: "0 0 5px rgba(0,0,0,0.7)",
                }}
              >
                {exp.date}
              </span>
            }
            iconStyle={{
              background: iconBgGradient,
              color: "#fff",
              boxShadow: "0 0 10px rgba(0,0,0,0.4)",
            }}
            contentStyle={{
              background: contentBgGradient,
              color: "#fff",
              boxShadow: "0 4px 15px rgba(0,0,0,0.3)",
              padding: "12px 15px", // padding uniforme y no excesivo
            }}
            contentArrowStyle={{
              borderRight: `7px solid ${arrowBorderColor}`,
            }}
            style={{ marginBottom: "6px", marginTop: "6px" }} // menos espacio vertical
            icon={exp.icon}
          >
            <h3
              style={{
                fontSize: isUniversityOrCloud ? "1rem" : "1.3rem",
                marginBottom: 4,
              }}
            >
              {exp.title}
            </h3>
            <h4
              style={{
                fontSize: isUniversityOrCloud ? "0.85rem" : "1.1rem",
                marginTop: 0,
              }}
            >
              {exp.company}
            </h4>
          </VerticalTimelineElement>
        );
      })}
    </VerticalTimeline>
  );
}
